var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"바람은 늘 제게 속삭여 주고 있어요.","JPN":"風はいつも私に囁いてくれてるんです。","ENG":"The wind always whispers to me.","TWN":"風總是會對我低喃。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"주변 사람들은 어떤 이야기를 들었는지 궁금해했지만...... 그들이 바라는 건 개인의 영달이나 부귀영화에 대한 것뿐이죠.","JPN":"周りの人たちはどんな話を聞いたのか気にしているようでしたが……\\n彼らは、自分の栄耀栄華に関することだけを気にしていました。","ENG":"People around me are curious what it was that I heard, but what they really want is something that could help them attain their personal profit.","TWN":"周圍的人都很好奇我聽到了什麼事情……但他們期望的，不過是榮華富貴罷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"하지만 제게 들리던 이야기는 사람들의 흥미와 동떨어진 내용이었어요.","JPN":"しかし、私が聞いたのは、人々が興味を持っているものとかけ離れた内容でした。","ENG":"But what I hear is far from what people are interested in.","TWN":"而我聽到的事情，也與人們的興趣相去甚遠。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"고통 받았던 이들의 저주, 고통 받는 사람들의 비명......","JPN":"苦しんでいた者たちの呪い、今も苦しんでいる者たちの悲鳴……","ENG":"Curses of the people who suffered, screams of the ones who are suffering...","TWN":"受難者的詛咒，受苦者的悲鳴……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"그리고...... 고통 받을 이들의 통곡까지.","JPN":"そして……苦しんでいくの者たちの慟哭も。","ENG":"And sometimes... Cries of the people who are bound to suffer.","TWN":"還有……連同那些將要受苦的人們，他們的哭號。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"오래된 전승에 따르면, 저희 가문은 예로부터 이면세계와 맞섰다고 합니다.","JPN":"古き伝承によりますと、私の家門は昔からカウンターサイドに立ち向かってきたそうです。","ENG":"Old legends say that my family has fought the enemies of the Counterside for ages.","TWN":"根據古老的傳承所說，我們家族自古以來就在對抗異界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"선조께서 이 힘으로 가문을 일으켜 세우신 건 부와 명예를 취해서가 아니었어요.","JPN":"ご先祖様がこの力で家門を立て直してくださったのは、\\n富や名誉を得るためではありませんでした。","ENG":"My family didn't prosper because of the wealth and fame my ancestors earned with this power,","TWN":"祖先能用這個力量建立起家族，不是因為財富和名譽。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"그분이 이면세계의 위협으로부터 구한 분들의 믿음과 성원이 있었기에 가능했던 것이죠.","JPN":"ご先祖様にカウンターサイドの脅威から救われた方々の信頼や声援があったからこそ、可能なことでした。","ENG":"but because of the trust and support they received from the people saved from the threats of the Counterside.","TWN":"而是從異界的威脅中拯救出來的那些人，受到他們的信賴和支持，才能辦到的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"가문이 쇠락했던 것은...... 그러한 기원을 잊고 지냈기 때문이라고, 저는 생각해요.","JPN":"七原家が衰退したのは……そのような由来を忘れていたからだと、私は思います。","ENG":"And my family had to experience a decline because we forgot where we came from. At least that's how I see it.","TWN":"而家族的衰落……我想就是因為我們忘記了這份初衷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"바람은 늘 제게 물어 왔어요. 그 많은 이들의 슬픔을 어떻게 막아야 할지.","JPN":"風はいつも私に聞いてきました。無数の者たちの悲しみを、如何にして断ち切るのか。","ENG":"The wind always asked me. The wind wanted to know how we could drive away this mountain of despair reserved for so many people.","TWN":"風總是在問我，要怎麼阻止人們的悲傷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"그리고 당신과 지내면서 확신하게 되었어요.","JPN":"そして、社長と過ごしてる間に確信するようになりました。","ENG":"Then, while spending time with you, I realized.","TWN":"然後，和您一起度過的這些日子中，我確信了這件事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"이 분과 함께라면...... 가능하다고.","JPN":"この方とともにすれば……可能なんだと。","ENG":"With you, we could do it.","TWN":"和您這位大人在一起……就有可能。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"전 올바른 전통을 받들어 세계를 지키기 위한 일에 헌신하기로 정한 몸, 마음의 준비는 이미 끝마쳤습니다.","JPN":"私は正しい伝統を受け継いで世界を守ることに献身すると決めた身、心の準備はもうできています。","ENG":"I've decided to be the rightful heir of the sacred tradition and devote myself to protecting the world. My determination is firm.","TWN":"決心獻身於正統，致志於守護世界，我的身心都做好了準備。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SETSUNA_JAPAN_NULL_CHANGE","text":{"KOREA":"그러니 부디...... 원하시는 대로.","JPN":"ですからどうか……お望みのままに。","ENG":"So please, do as you wish.","TWN":"所以請務必要……如您所願。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SETSUNA_JAPAN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};